/**
 * Apply translations to the current page.
 * @param {string} lang - 'en' or 'ru'
 */
function applyTranslations(lang) {
    document.querySelectorAll('[data-i18n]').forEach(el => {
        const key = el.getAttribute('data-i18n');
        if (translations[key] && translations[key][lang] !== undefined) {
            const val = translations[key][lang];
            if (el.tagName === 'INPUT' || el.tagName === 'TEXTAREA') {
                el.setAttribute('placeholder', val);
            } else {
                el.innerHTML = val;
            }
        }
    });

    // List items with data-i18n-list (tour inclusions / not-included)
    document.querySelectorAll('[data-i18n-list]').forEach(ul => {
        const key = ul.getAttribute('data-i18n-list');
        if (translations[key] && translations[key][lang]) {
            const items = translations[key][lang];
            ul.innerHTML = items.map(t => `<li>${t}</li>`).join('');
        }
    });

    // Page title
    const pgKey = document.documentElement.getAttribute('data-page');
    if (pgKey && translations[pgKey] && translations[pgKey][lang]) {
        document.title = translations[pgKey][lang];
    }

    // Update html lang attribute
    document.documentElement.lang = lang;

    // Persist choice
    localStorage.setItem('sok_lang', lang);

    // Update switcher buttons
    document.querySelectorAll('.lang-btn').forEach(btn => {
        btn.classList.toggle('active', btn.getAttribute('data-lang') === lang);
    });
}

function initI18n() {
    const saved = localStorage.getItem('sok_lang') || 'en';
    applyTranslations(saved);

    document.querySelectorAll('.lang-btn').forEach(btn => {
        btn.addEventListener('click', () => {
            applyTranslations(btn.getAttribute('data-lang'));
        });
    });
}

document.addEventListener('DOMContentLoaded', initI18n);
